// Extract deal_id from webhook body
const body = $input.first().json.body || $input.first().json;
const deal_id = body.deal_id;

if (!deal_id) throw new Error('Missing required field: deal_id');

return [{ json: { deal_id } }];

// Core AD gap assessment logic.
// Reads Agent 2's freshly written deal_health row and the existing approach_doc state.
// Produces a list of gap items to queue as drafts in Agent 3.

const health = $('Postgres: Get Latest Deal Health').first().json;
const adRow = $('Postgres: Get Existing Approach Doc').first().json;
const deal_id = health.deal_id;
const today = new Date();

// Check hold
if (health.hold_until && new Date(health.hold_until) > today) {
  return [{ json: { gaps: [], skipped_reason: 'hold_until: ' + health.hold_until } }];
}

// Parse inferred workstreams from deal_health
let workstreams = [];
try {
  const raw = health.inferred_workstreams;
  if (Array.isArray(raw)) workstreams = raw;
  else if (typeof raw === 'string') workstreams = JSON.parse(raw);
} catch(e) { workstreams = []; }

// Parse workstream rows from approach_doc query
let wsRows = [];
try {
  const raw = adRow.workstreams;
  if (Array.isArray(raw)) wsRows = raw;
  else if (typeof raw === 'string') wsRows = JSON.parse(raw);
} catch(e) { wsRows = []; }

const draft_counts = {
  pricing_request: parseInt(adRow.draft_pricing_request || 0),
  internal_team_update: parseInt(adRow.draft_internal_update || 0)
};

const gaps = [];

// --- EXTERNAL: Always queue follow-up correspondence after every scoring run ---
gaps.push({
  deal_id,
  output_type: 'follow_up_email',
  recipient_email: null,
  recipient_name: null,
  instructions: `This is an external communication. Draft the appropriate outbound follow-up to the client contacts based on what was most recently received for ${health.company_name}. If a call transcript was ingested, summarize the call and confirm next steps. If an email or document was received, acknowledge it and respond appropriately. Address all relevant client contacts from the most recent interaction. Preview only — do not send.`,
  triggered_by: 'ad_tracker',
  preview_mode: true,
  lane: 'external'
});

// --- INTERNAL: Pricing not yet requested for any inferred workstream ---
const pricingAlreadyRequested = adRow.pricing_requested === true;
const hasDraftPricingRequest = draft_counts.pricing_request > 0;

if (workstreams.length > 0 && !pricingAlreadyRequested && !hasDraftPricingRequest) {
  const steveAkersSlugs = ['managed_azure_cloud', 'managed_security_healthcare', 'managed_soc', 'mdr', 'mss'];
  const needsSteve = workstreams.some(slug => steveAkersSlugs.includes(slug));
  const recipientEmail = needsSteve ? 'steve.akers@clearwatersecurity.com' : 'carter.lankford@clearwatersecurity.com';
  const recipientName = needsSteve ? 'Steve Akers' : 'Carter Lankford';

  gaps.push({
    deal_id,
    output_type: 'pricing_request',
    recipient_email: recipientEmail,
    recipient_name: recipientName,
    instructions: `This is an internal communication. Draft a message to ${recipientName} in the tone you would use with an internal Clearwater colleague. Request pricing for the following workstreams: ${workstreams.join(', ')}. Company: ${health.company_name}. Deal stage: ${health.deal_stage}.`,
    triggered_by: 'ad_tracker',
    lane: 'internal'
  });
}

// --- INTERNAL: Scoping missing for any workstream ---
const unscopedWorkstreams = wsRows.filter(ws =>
  ws.scoping_status === 'missing' || ws.scoping_status === 'partial'
);
if (unscopedWorkstreams.length > 0 && draft_counts.internal_team_update === 0) {
  gaps.push({
    deal_id,
    output_type: 'internal_team_update',
    recipient_email: 'austin.holland@clearwatersecurity.com',
    recipient_name: 'Austin Holland',
    instructions: `This is an internal communication. Draft a message in the tone you would use with an internal Clearwater colleague. Flag that scoping is incomplete for: ${unscopedWorkstreams.map(w => w.service_slug).join(', ')}. Company: ${health.company_name}. Deal stage: ${health.deal_stage}. Note what scoping questions are still outstanding.`,
    triggered_by: 'ad_tracker',
    lane: 'internal'
  });
}

// --- INTERNAL: DC not assigned for any workstream ---
const unassigned = wsRows.filter(ws => !ws.dc_assigned_name);
if (unassigned.length > 0 && wsRows.length > 0 && !adRow.dc_principal_name && draft_counts.internal_team_update === 0) {
  gaps.push({
    deal_id,
    output_type: 'internal_team_update',
    recipient_email: 'austin.holland@clearwatersecurity.com',
    recipient_name: 'Austin Holland',
    instructions: `This is an internal communication. Draft a message in the tone you would use with an internal Clearwater colleague. Flag that no Delivery Consultant has been assigned for: ${unassigned.map(w => w.service_slug).join(', ')}. Company: ${health.company_name}. Deal stage: ${health.deal_stage}. Follow up with the Delivery team.`,
    triggered_by: 'ad_tracker',
    lane: 'internal'
  });
}

return gaps.map(g => ({ json: g }));

// Upsert approach_doc and deal_workstreams for this deal.
// Runs after gap assessment (whether or not gaps were found).
// Gathers all upstream data.

const dealId = $('Code: Extract Deal ID').first().json.deal_id;
const health = $('Postgres: Get Latest Deal Health').first().json;
const adRow = $('Postgres: Get Existing Approach Doc').first().json;

// Parse inferred workstreams
let workstreams = [];
try {
  const raw = health.inferred_workstreams;
  if (Array.isArray(raw)) workstreams = raw;
  else if (typeof raw === 'string') workstreams = JSON.parse(raw);
} catch(e) { workstreams = []; }

function sq(v) {
  if (v === null || v === undefined || v === '') return 'NULL';
  return "'" + String(v).replace(/'/g, "''") + "'";
}
function sb(v) { return v ? 'TRUE' : 'FALSE'; }

// Upsert approach_doc — only set fields we have data for
const approachDocSql = `INSERT INTO approach_doc (deal_id, last_updated_at)
VALUES (${sq(dealId)}, NOW())
ON CONFLICT (deal_id) DO UPDATE SET last_updated_at = NOW()`;

// Upsert deal_workstreams — one row per inferred workstream (confidence='inferred' until confirmed)
let workstreamsSql = 'SELECT 1'; // no-op if no workstreams
if (workstreams.length > 0) {
  const rows = workstreams.map(slug =>
    `(${sq(dealId)}, ${sq(slug)}, 'inferred', 'missing', 'not_requested', NOW(), NOW())`
  ).join(',\n');
  workstreamsSql = `INSERT INTO deal_workstreams
  (deal_id, service_slug, confidence, scoping_status, pricing_status, first_inferred_at, last_updated_at)
VALUES ${rows}
ON CONFLICT (deal_id, service_slug) DO UPDATE SET last_updated_at = NOW()`;
}

return [{ json: { approach_doc_sql: approachDocSql, workstreams_sql: workstreamsSql, deal_id: dealId } }];

// Final logging node — signals AD Tracker pipeline complete
const dealId = $('Code: Extract Deal ID').first().json.deal_id;
return [{ json: { status: 'ad_tracker_complete', deal_id: dealId } }];

// Extract deal_id from webhook body
const body = $input.first().json.body || $input.first().json;
const deal_id = body.deal_id;

if (!deal_id) throw new Error('Missing required field: deal_id');

return [{ json: { deal_id } }];

