// Reads Agent 2's freshly written deal_health row and the existing approach_doc state.
// Produces a list of gap items to queue as drafts in Agent 3.

const health = $('Postgres: Get Latest Deal Health').first().json;
const adRow = $('Postgres: Get Existing Approach Doc').first().json;
const deal_id = health.deal_id;
const today = new Date();
const stage = (health.deal_stage || '').toLowerCase();

// Normalize stage: qualify, prove, negotiate, close
const activeStages = ['qualify', 'prove', 'negotiate', 'close'];
if (!activeStages.includes(stage)) {
  return [{ json: { gaps: [], skipped_reason: `deal in ${stage || 'discover'} stage — no AD assessment needed` } }];
}

// Check hold
if (health.hold_until && new Date(health.hold_until) > today) {
  return [{ json: { gaps: [], skipped_reason: 'hold_until: ' + health.hold_until } }];
}

// Parse inferred workstreams from deal_health
// inferred_workstreams is a JSONB array of service_slug strings
let workstreams = [];
try {
  const raw = health.inferred_workstreams;
  if (Array.isArray(raw)) workstreams = raw;
  else if (typeof raw === 'string') workstreams = JSON.parse(raw);
} catch(e) { workstreams = []; }

// Parse workstream rows from approach_doc query
let wsRows = [];
try {
  const raw = adRow.workstreams;
  if (Array.isArray(raw)) wsRows = raw;
  else if (typeof raw === 'string') wsRows = JSON.parse(raw);
} catch(e) { wsRows = []; }

const draft_counts = {
  pricing_request: parseInt(adRow.draft_pricing_request || 0),
  internal_team_update: parseInt(adRow.draft_internal_update || 0),
  pre_call_planner: parseInt(adRow.draft_pre_call_planner || 0)
};

const gaps = [];

// --- Gap 1: Pricing not yet requested for any inferred workstream ---
// Only queue if: workstreams identified AND pricing not already requested AND no draft pending
const pricingAlreadyRequested = adRow.pricing_requested === true;
const hasDraftPricingRequest = draft_counts.pricing_request > 0;

if (workstreams.length > 0 && !pricingAlreadyRequested && !hasDraftPricingRequest) {
  // Steve Akers handles Managed Cloud / Azure workstreams
  const steveAkersSlugs = ['managed_azure_cloud', 'managed_security_healthcare', 'managed_soc', 'mdr', 'mss'];
  const needsSteve = workstreams.some(slug => steveAkersSlugs.includes(slug));
  const pricingContact = needsSteve ? 'steve_akers' : 'carter';
  const recipientEmail = needsSteve ? 'steve.akers@clearwatersecurity.com' : 'carter.lankford@clearwatersecurity.com';
  const recipientName = needsSteve ? 'Steve Akers' : 'Carter Lankford';

  gaps.push({
    deal_id,
    output_type: 'pricing_request',
    recipient_email: recipientEmail,
    recipient_name: recipientName,
    instructions: `Workstreams identified: ${workstreams.join(', ')}. Company: ${health.company_name}. Deal stage: ${stage}. Generate pricing request draft (format TBD — placeholder only, do not send).`,
    triggered_by: 'ad_tracker'
  });
}

// --- Gap 2: Scoping missing for confirmed workstreams (Prove+ stage only) ---
if (['prove', 'negotiate', 'close'].includes(stage)) {
  const unscopedWorkstreams = wsRows.filter(ws =>
    ws.scoping_status === 'missing' || ws.scoping_status === 'partial'
  );
  if (unscopedWorkstreams.length > 0 && draft_counts.internal_team_update === 0) {
    gaps.push({
      deal_id,
      output_type: 'internal_team_update',
      recipient_email: 'austin.holland@clearwatersecurity.com',
      recipient_name: 'Austin Holland',
      instructions: `Scoping incomplete for: ${unscopedWorkstreams.map(w => w.service_slug).join(', ')}. Company: ${health.company_name}. Deal stage: ${stage}. Flag for next call prep — what questions are still outstanding?`,
      triggered_by: 'ad_tracker'
    });
  }
}

// --- Gap 3: DC not assigned for any workstream (Prove+ stage) ---
if (['prove', 'negotiate', 'close'].includes(stage)) {
  const unassigned = wsRows.filter(ws => !ws.dc_assigned_name);
  // Only flag if there are workstreams and none have a DC yet
  if (unassigned.length > 0 && wsRows.length > 0 && !adRow.dc_principal_name && draft_counts.internal_team_update === 0) {
    gaps.push({
      deal_id,
      output_type: 'internal_team_update',
      recipient_email: 'austin.holland@clearwatersecurity.com',
      recipient_name: 'Austin Holland',
      instructions: `No Delivery Consultant assigned for: ${unassigned.map(w => w.service_slug).join(', ')}. Company: ${health.company_name}. Deal stage: ${stage}. Check with Delivery team.`,
      triggered_by: 'ad_tracker'
    });
  }
}

// --- Gap 4: Pre-call planner (upcoming call within 3 days) ---
if (health.next_step_date) {
  const nextDate = new Date(health.next_step_date);
  const daysUntilNext = Math.floor((nextDate - today) / 86400000);
  const hasPendingPreCall = draft_counts.pre_call_planner > 0;

  if (daysUntilNext >= 0 && daysUntilNext <= 3 && !hasPendingPreCall) {
    const scopingGaps = wsRows
      .filter(ws => ws.scoping_status !== 'complete')
      .map(ws => ws.service_slug);
    gaps.push({
      deal_id,
      output_type: 'pre_call_planner',
      recipient_email: 'austin.holland@clearwatersecurity.com',
      recipient_name: 'Austin Holland',
      instructions: `Upcoming call in ${daysUntilNext} day(s): ${health.next_step_date}. Focus: ${health.next_step || 'advance deal'}. Company: ${health.company_name}.`
        + (scopingGaps.length > 0 ? ` Scoping still needed for: ${scopingGaps.join(', ')}.` : ''),
      triggered_by: 'ad_tracker'
    });
  }
}

if (gaps.length === 0) {
  return [{ json: { gaps: [], skipped_reason: 'no gaps detected', deal_id } }];
}

// Return one item per gap — fan-out to HTTP: Queue Draft Outputs
return gaps.map(g => ({ json: g }));

// Upsert approach_doc and deal_workstreams for this deal.
// Runs after gap assessment (whether or not gaps were found).
// Gathers all upstream data.

const dealId = $('Code: Extract Deal ID').first().json.deal_id;
const health = $('Postgres: Get Latest Deal Health').first().json;
const adRow = $('Postgres: Get Existing Approach Doc').first().json;

// Parse inferred workstreams
let workstreams = [];
try {
  const raw = health.inferred_workstreams;
  if (Array.isArray(raw)) workstreams = raw;
  else if (typeof raw === 'string') workstreams = JSON.parse(raw);
} catch(e) { workstreams = []; }

